source:
Locale -> {
  String:code
  String:name
}

fr -> Locale{code -> "fr" name -> "Francais"}
en -> Locale{code -> "en" name -> "English"}

Translator -> {
  Locale:current -> en
  Locale:fallback -> en
}

translate -> {
  Translator:t
  String:key
  -> key ? {
    "hello" -> t.current.code
    "bye" -> t.fallback.code
    -> key
  }
}
